using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<ResearchTools>();
builder.Services.AddSingleton<NoteService>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteService = host.Services.GetRequiredService<NoteService>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. Given a topic, use the WebSearch tool to find "
    + "information, then use the AddNote tool to record key findings. After gathering "
    + "enough information (at least 2-3 searches), use AddNote to save a final summary, "
    + "then present your findings to the user.");

var tools = new[]
{
    AIFunctionFactory.Create(researchTools.WebSearch),
    AIFunctionFactory.Create(noteService.AddNote),
    AIFunctionFactory.Create(noteService.GetNotes),
};

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    noteService.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and summarize your findings: {topic}"),
    };

    var options = new AgentInvokeOptions
    {
        MaximumIterations = 10,
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    };

    Console.WriteLine($"\nResearching \"{topic}\"...\n");

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(history, options))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
            {
                Console.Write(message.Text);
            }
        }

        Console.WriteLine("\n");

        if (noteService.Notes.Count > 0)
        {
            Console.WriteLine("--- Saved Notes ---");
            foreach (var note in noteService.Notes)
            {
                Console.WriteLine($"  • {note}");
            }
            Console.WriteLine();
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye!");

// -- Tool classes ----------------------------------------------------------

public sealed class NoteService
{
    private readonly List<string> _notes = [];
    public IReadOnlyList<string> Notes => _notes;

    [Description("Saves a research note or finding. Use this to record key facts, insights, or a final summary.")]
    public string AddNote([Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Returns all notes saved so far during this research session.")]
    public IReadOnlyList<string> GetNotes() => _notes;

    public void Clear() => _notes.Clear();
}

public sealed class ResearchTools
{
    private static readonly Dictionary<string, string[]> SimulatedResults = new(StringComparer.OrdinalIgnoreCase)
    {
        ["quantum computing"] =
        [
            "Quantum computers use qubits that can exist in superposition, enabling parallel computation. IBM and Google lead with 1000+ qubit processors as of 2025.",
            "Key applications include cryptography (Shor's algorithm), drug discovery via molecular simulation, and optimization problems in logistics.",
            "Current challenges: error correction, decoherence, and the need for near-absolute-zero temperatures. Fault-tolerant quantum computing remains years away.",
        ],
        ["artificial intelligence"] =
        [
            "Large Language Models (LLMs) like GPT-4o and Claude have driven rapid AI adoption in enterprise settings, with applications in code generation, customer support, and data analysis.",
            "AI safety and alignment research has become a major focus, with organizations like Anthropic and OpenAI investing heavily in interpretability and constitutional AI approaches.",
            "Edge AI and on-device inference are growing trends, with frameworks like ONNX Runtime enabling efficient model deployment on mobile and IoT devices.",
        ],
    };

    [Description("Searches the web for information about a query. Returns a list of relevant search results.")]
    public string[] WebSearch([Description("The search query")] string query)
    {
        foreach (var (key, results) in SimulatedResults)
        {
            if (query.Contains(key, StringComparison.OrdinalIgnoreCase))
                return results;
        }

        return
        [
            $"'{query}' is a topic of active research with many recent developments and academic publications.",
            $"Experts in the field of '{query}' suggest significant breakthroughs are expected in the coming years.",
            $"Industry applications of '{query}' span healthcare, finance, education, and environmental science.",
        ];
    }
}

