arguments.old_str:
using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<ResearchTools>();
builder.Services.AddSingleton<NoteService>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteService = host.Services.GetRequiredService<NoteService>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. Given a topic, use the WebSearch tool to find "
    + "information, then use the AddNote tool to record key findings. After gathering "
    + "enough information (at least 2-3 searches), use AddNote to save a final summary, "
    + "then present your findings to the user.");

var tools = new[]
{
    AIFunctionFactory.Create(researchTools.WebSearch),
    AIFunctionFactory.Create(noteService.AddNote),
    AIFunctionFactory.Create(noteService.GetNotes),
};

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    noteService.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and summarize your findings: {topic}"),
    };

    var options = new AgentInvokeOptions
    {
        MaximumIterations = 10,
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    };

    Console.WriteLine($"\nResearching \"{topic}\"...\n");

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(history, options))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
            {
                Console.Write(message.Text);
            }
        }

        Console.WriteLine("\n");

        if (noteService.Notes.Count > 0)
        {
            Console.WriteLine("--- Saved Notes ---");
            foreach (var note in noteService.Notes)
            {
                Console.WriteLine($"  • {note}");
            }
            Console.WriteLine();
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye!");

arguments.new_str:
using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(pipeline => pipeline
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<NoteService>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteService = host.Services.GetRequiredService<NoteService>();
var researchTools = new ResearchTools();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.WebSearch),
    AIFunctionFactory.Create(noteService.AddNote),
    AIFunctionFactory.Create(noteService.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a research assistant. Given a topic, use the WebSearch tool to find "
        + "information, then use the AddNote tool to record key findings. Perform at least "
        + "2-3 searches with different queries to get broad coverage. After gathering enough "
        + "information, use AddNote to save a final summary, then present your consolidated "
        + "findings to the user.",
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools.",
    tools: tools);

Console.WriteLine("=== Research Agent ===");
